1	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
2	type Customer = { yearsWithMHPCO: number };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
7	type Step = QuoteStep | ClaimStep;
8	type Scenario = { customer: Customer; steps: Step[] };
9	type Policy = { items: Item[]; remainingCap: number };
10	
11	const PROCESSING_FEE = 5;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
15	const CLAIM_HIGH_ENCHANTMENT_RATE = 0.5;
16	
17	const INSURANCE_VALUE: Record<string, number> = {
18	  sword: 1000,
19	  amulet: 600,
20	  staff: 800,
21	  potion: 400,
22	  rune: 250,
23	  moonstone: 250,
24	};
25	
26	const FIRST_INSURANCE_RATE = 0.1;
27	const CURSE_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_RATE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	const LOYALTY_THRESHOLD_YEARS = 2;
32	const FOLLOWUP_DISCOUNT_RATE = 0.15;
33	
34	const COMPONENT_BLOCK_SIZE = 3;
35	const COMPONENT_BLOCK_PRICE = 60;
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	const BASE_PREMIUM: Record<string, number> = {
39	  sword: 100,
40	  amulet: 60,
41	  staff: 80,
42	  potion: 40,
43	  rune: 25,
44	  moonstone: 25,
45	};
46	
47	// MHPCO always rounds in its own favor: premiums (customer pays) round UP,
48	// payouts (MHPCO pays) round DOWN.
49	const roundPremiumInMHPCOFavor = (amount: number): number => Math.ceil(amount);
50	const roundPayoutInMHPCOFavor = (amount: number): number => Math.floor(amount);
51	
52	const countBy = <T>(items: T[], keyOf: (item: T) => string): Record<string, number> => {
53	  const counts: Record<string, number> = {};
54	  for (const item of items) counts[keyOf(item)] = (counts[keyOf(item)] ?? 0) + 1;
55	  return counts;
56	};
57	
58	const countByType = (items: Item[]): Record<string, number> =>
59	  countBy(items, (item) => item.type);
60	
61	const qualifiesForComponentBlock = (type: string, count: number): boolean =>
62	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
63	
64	const lineItemPrice = (type: string, count: number): number =>
65	  qualifiesForComponentBlock(type, count)
66	    ? COMPONENT_BLOCK_PRICE
67	    : BASE_PREMIUM[type] * count;
68	
69	const sumBasePremiums = (items: Item[]): number =>
70	  Object.entries(countByType(items))
71	    .reduce((total, [type, count]) => total + lineItemPrice(type, count), 0);
72	
73	const rateOf = (amount: number, rate: number, applies: boolean): number =>
74	  applies ? amount * rate : 0;
75	
76	const isCursed = (item: Item): boolean => item.cursed === true;
77	
78	const enchantmentAtLeast = (item: Item, threshold: number): boolean =>
79	  (item.enchantment ?? 0) >= threshold;
80	
81	const isHighlyEnchanted = (item: Item): boolean =>
82	  enchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD);
83	
84	const itemSurcharges = (items: Item[]): number =>
85	  items.reduce((sum, item) => {
86	    const base = BASE_PREMIUM[item.type];
87	    return sum
88	      + rateOf(base, CURSE_SURCHARGE_RATE, isCursed(item))
89	      + rateOf(base, HIGH_ENCHANTMENT_RATE, isHighlyEnchanted(item));
90	  }, 0);
91	
92	const isLoyalCustomer = (customer: Customer): boolean =>
93	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
94	
95	const isFollowupContract = (stepIndex: number): boolean => stepIndex > 0;
96	
97	const quotePremium = (items: Item[], customer: Customer, stepIndex: number): number => {
98	  const basePremium = sumBasePremiums(items);
99	  const surcharges = itemSurcharges(items);
100	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
101	  const loyaltyDiscount = rateOf(basePremium, LOYALTY_DISCOUNT_RATE, isLoyalCustomer(customer));
102	  const followupDiscount = rateOf(basePremium, FOLLOWUP_DISCOUNT_RATE, isFollowupContract(stepIndex));
103	  return roundPremiumInMHPCOFavor(basePremium + surcharges + firstInsurance - loyaltyDiscount - followupDiscount + PROCESSING_FEE);
104	};
105	
106	const validateItems = (items: Item[]): void => {
107	  for (const item of items) {
108	    if (!(item.type in BASE_PREMIUM)) {
109	      throw new Error(`Unknown item type: ${item.type}`);
110	    }
111	  }
112	};
113	
114	const insuranceSum = (items: Item[]): number =>
115	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
116	
117	const reimbursableAmount = (item: Item, amount: number): number =>
118	  enchantmentAtLeast(item, CLAIM_HIGH_ENCHANTMENT_THRESHOLD)
119	    ? amount * CLAIM_HIGH_ENCHANTMENT_RATE
120	    : amount;
121	
122	const damagePayout = (damage: Damage, policy: Policy): number => {
123	  const item = policy.items.find((i) => i.type === damage.itemType)!;
124	  return reimbursableAmount(item, damage.amount) - DEDUCTIBLE;
125	};
126	
127	const uncappedPayout = (incident: Incident, policy: Policy): number =>
128	  incident.damages.reduce((sum, dmg) => sum + damagePayout(dmg, policy), 0);
129	
130	const validateDamages = (policy: Policy, incident: Incident): void => {
131	  const policyCounts = countByType(policy.items);
132	  const damageCounts = countBy(incident.damages, (dmg) => dmg.itemType);
133	  for (const [type, count] of Object.entries(damageCounts)) {
134	    if (count > (policyCounts[type] ?? 0)) {
135	      throw new Error(`Too many damages for item type: ${type}`);
136	    }
137	  }
138	};
139	
140	const processClaim = (policy: Policy, incident: Incident): { payout: number; remainingCap: number } => {
141	  validateDamages(policy, incident);
142	  const payout = Math.min(roundPayoutInMHPCOFavor(uncappedPayout(incident, policy)), policy.remainingCap);
143	  policy.remainingCap -= payout;
144	  return { payout, remainingCap: policy.remainingCap };
145	};
146	
147	const processQuote = (step: QuoteStep, customer: Customer, stepIndex: number): { policy: Policy; premium: number } => {
148	  validateItems(step.items);
149	  const policy: Policy = { items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER };
150	  return { policy, premium: quotePremium(step.items, customer, stepIndex) };
151	};
152	
153	export const runScenario = (input: unknown): unknown => {
154	  const scenario = input as Scenario;
155	  const policies: Policy[] = [];
156	  const results = scenario.steps.map((step, index) => {
157	    if (step.op === "quote") {
158	      const { policy, premium } = processQuote(step, scenario.customer, index);
159	      policies[index] = policy;
160	      return { premium };
161	    }
162	    return processClaim(policies[step.policy], step.incident);
163	  });
164	  return { results };
165	};
